#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 1e5+5;
LL T,p[N],cnt,mu[N],sm[N];
bool vis[N];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void init(){
    vis[0]=1,vis[1]=1;
    mu[1]=1,cnt=0;
    for(LL i=2;i<=50000;i++){
        if(!vis[i])p[++cnt]=i,mu[i]=-1;
        for(int j=1;j<=cnt&&i*p[j]<=50000;j++){
            vis[i*p[j]]=1;
            if(i%p[j]==0)break;
            else mu[i*p[j]]=-mu[i];
        }
    }for(int i=1;i<=50000;i++)
        sm[i]=sm[i-1]+mu[i];return;
}
LL sol(LL n,LL m,LL k){
    if(!n||!m)return 0;
    LL res=0;n/=k,m/=k;
    if(n>m)swap(n,m);
    for(int l=1,r;l<=n;l=r+1){
        r=min(n/(n/l),m/(m/l));
        res+=(sm[r]-sm[l-1])*(n/l)*(m/l);
    }return res;
}
int main(){
    T=read();init();
    while(T--){
        LL a=read(),b=read();
        LL c=read(),d=read(),k=read();
        LL tmp=sol(b,d,k)-sol(b,c-1,k)-sol(a-1,d,k);
        cout<<tmp+sol(a-1,c-1,k)<<"\n";
    }
    return 0;
}
